#include<bits/stdc++.h>
#include<ext/rope>
using namespace std;
__gnu_cxx::rope<int> v;
string name[1000010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        cin>>name[i];
        v.push_back(i);
    }
    int m;
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        cin>>name[i+n];
        int p;
        scanf("%d",&p);
        v.insert(p,i+n);
    }
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int x;
        scanf("%d",&x);
        cout<<name[v[x]]<<"\n";
    }
    return 0;
}
